## Common patterns

### Comment input with character limit

Track character count and enforce limits for user-generated content:

```jsx live-dev
const App = () => {
  const [comment, setComment] = useState<string>('');
  const maxLength = 280;
  const remaining = maxLength - comment.length;
  const isOverLimit = remaining < 0;

  return (
    <Stack direction="column" gap="400">
      <MultilineTextInput
        value={comment}
        onChange={setComment}
        placeholder="Share your thoughts..."
        rows={4}
        isInvalid={isOverLimit}
        leadingElement={<Icons.Comment />}
      />
      <Stack direction="row" justifyContent="space-between">
        <Text fontSize="sm" color={isOverLimit ? 'critical.11' : 'neutral.11'}>
          {remaining} characters remaining
        </Text>
        <Button
          size="xs"
          isDisabled={comment.length === 0 || isOverLimit}
        >
          Post Comment
        </Button>
      </Stack>
    </Stack>
  );
}
```

### Auto-growing feedback form

Create responsive form fields that adapt to content length:

```jsx live-dev
const App = () => {
  const [feedback, setFeedback] = useState<string>('');
  const wordCount = feedback.trim().split(/\s+/).filter(Boolean).length;

  return (
    <Stack direction="column" gap="400">
      <Text fontWeight="semibold">Share Your Feedback</Text>
      <MultilineTextInput
        autoGrow
        value={feedback}
        onChange={setFeedback}
        placeholder="Tell us about your experience..."
        minH="1600"
        maxH="4800"
        leadingElement={<Icons.Feedback />}
      />
      <Stack direction="row" justifyContent="space-between" alignItems="center">
        <Text fontSize="sm" color="neutral.11">
          {wordCount} {wordCount === 1 ? 'word' : 'words'}
        </Text>
        <Button size="xs" isDisabled={wordCount < 10}>
          Submit Feedback
        </Button>
      </Stack>
    </Stack>
  );
}
```

### Multi-field form with validation

Combine multiple textareas in a form with validation states:

```jsx live-dev
const App = () => {
  const [title, setTitle] = useState<string>('');
  const [description, setDescription] = useState<string>('');
  const [touched, setTouched] = useState({ title: false, description: false });

  const titleError = touched.title && title.length < 5;
  const descError = touched.description && description.length < 20;

  return (
    <Stack direction="column" gap="600">
      <Stack direction="column" gap="300">
        <Text fontWeight="semibold">Title *</Text>
        <MultilineTextInput
          value={title}
          onChange={setTitle}
          onBlur={() => setTouched(prev => ({ ...prev, title: true }))}
          placeholder="Brief summary (minimum 5 characters)"
          rows={1}
          isInvalid={titleError}
          isRequired
        />
        {titleError && (
          <Text fontSize="sm" color="critical.11">
            Title must be at least 5 characters
          </Text>
        )}
      </Stack>

      <Stack direction="column" gap="300">
        <Text fontWeight="semibold">Description *</Text>
        <MultilineTextInput
          autoGrow
          value={description}
          onChange={setDescription}
          onBlur={() => setTouched(prev => ({ ...prev, description: true }))}
          placeholder="Detailed explanation (minimum 20 characters)"
          minH="2400"
          maxH="4800"
          isInvalid={descError}
          isRequired
        />
        {descError && (
          <Text fontSize="sm" color="critical.11">
            Description must be at least 20 characters
          </Text>
        )}
      </Stack>

      <Button
        isDisabled={!title || !description || titleError || descError}
      >
        Submit
      </Button>
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using MultilineTextInput within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { MultilineTextInput, NimbusProvider } from "@commercetools/nimbus";
import { useState } from "react";

describe("MultilineTextInput - Basic rendering", () => {
  it("renders textarea element", () => {
    render(
      <NimbusProvider>
        <MultilineTextInput aria-label="Description" />
      </NimbusProvider>
    );

    const textarea = screen.getByRole("textbox", { name: /description/i });
    expect(textarea).toBeInTheDocument();
    expect(textarea.tagName).toBe("TEXTAREA");
  });

  it("renders with placeholder text", () => {
    render(
      <NimbusProvider>
        <MultilineTextInput
          placeholder="Enter your message"
          aria-label="Message"
        />
      </NimbusProvider>
    );

    expect(
      screen.getByPlaceholderText(/enter your message/i)
    ).toBeInTheDocument();
  });

  it("renders with specified number of rows", () => {
    render(
      <NimbusProvider>
        <MultilineTextInput rows={5} aria-label="Description" />
      </NimbusProvider>
    );

    const textarea = screen.getByRole("textbox");
    expect(textarea).toHaveAttribute("rows", "5");
  });
});
```

### Interaction Tests

Test user interactions with the textarea

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { MultilineTextInput, NimbusProvider } from "@commercetools/nimbus";
import { useState } from "react";

describe("MultilineTextInput - Interactions", () => {
  it("handles typing multi-line text", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <MultilineTextInput aria-label="Message" />
      </NimbusProvider>
    );

    const textarea = screen.getByRole("textbox");
    await user.type(textarea, "First line{Enter}Second line");

    expect(textarea).toHaveValue("First line\nSecond line");
  });

  it("calls onChange with typed value", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <MultilineTextInput onChange={handleChange} aria-label="Message" />
      </NimbusProvider>
    );

    const textarea = screen.getByRole("textbox");
    await user.type(textarea, "Hello");

    expect(handleChange).toHaveBeenCalledWith("Hello");
  });

  it("handles controlled mode updates", async () => {
    const { rerender } = render(
      <NimbusProvider>
        <MultilineTextInput
          value="Initial"
          onChange={() => {}}
          aria-label="Message"
        />
      </NimbusProvider>
    );

    const textarea = screen.getByRole("textbox");
    expect(textarea).toHaveValue("Initial");

    rerender(
      <NimbusProvider>
        <MultilineTextInput
          value="Updated"
          onChange={() => {}}
          aria-label="Message"
        />
      </NimbusProvider>
    );

    expect(textarea).toHaveValue("Updated");
  });
});
```

